// V17.0: 解析PG UNION ALL返回的3行JSON字符串
// bins 改用 bins_map 格式: { whs_code: [bin1, bin2, ...] } 压缩70K条→约1MB
// 严禁$('节点名')引用，仅使用$input
const rows = $input.all().map(r => r.json);

let items = [];
let warehouses = [];
let bins_map = {};
let binCount = 0;

for (const row of rows) {
  try {
    if (row._type === 'items') {
      const raw = JSON.parse(row._json || '[]');
      items = raw.map(r => ({ item_code: r.c, item_name: r.n, uom: r.u }));
    } else if (row._type === 'whs') {
      const raw = JSON.parse(row._json || '[]');
      warehouses = raw.map(r => ({ whs_code: r.c, whs_name: r.n }));
    } else if (row._type === 'bins') {
      const raw = JSON.parse(row._json || '[]');
      for (const r of raw) {
        const whs = r.w || '_';
        if (!bins_map[whs]) bins_map[whs] = [];
        bins_map[whs].push(r.c);
        binCount++;
      }
    }
  } catch(e) {
    // JSON解析失败，跳过该类型
  }
}

return { json: {
  success: true,
  items: items,
  warehouses: warehouses,
  bins_map: bins_map,
  counts: { items: items.length, warehouses: warehouses.length, bins: binCount }
} };
